async function callLLM(prompt, systemPrompt) {
  try {
    const response = await axios.post(
      OPENAI_API_URL,
      {
        model: 'gpt-4',
        messages: [
          {
            role: 'system',
            content: systemPrompt || 'You are an expert JavaScript programmer. Generate clean, efficient, and secure code based on user requirements. Return only the code without explanations or markdown formatting.'
          },
          {
            role: 'user',
            content: prompt
          }
        ],
        temperature: 0.7,
        max_tokens: 2000
      },
      {
        headers: {
          'Authorization': `Bearer ${OPENAI_API_KEY}`,
          'Content-Type': 'application/json'
        }
      }
    );

    return response.data.choices[0].message.content;
  } catch (error) {
    throw new Error(`LLM API Error: ${error.response?.data?.error?.message || error.message}`);
  }
}

